// Normaliza texto extraído del PDF.
// - Limpia whitespace y saltos de línea redundantes.
// - Trunca a 100.000 caracteres para proteger la ventana de contexto del LLM.

const MAX_CHARS = 100000;

return items.map((item) => {
  const j = item.json || {};
  const bin = item.binary?.data || {};

  let text = "";

  if (typeof j.text === "string") text = j.text;
  else if (typeof j.data === "string") text = j.data;
  else if (Array.isArray(j.data)) text = j.data.join("\n");
  else if (typeof j.content === "string") text = j.content;
  else if (typeof j.body === "string") text = j.body;

  text = (text || "")
    .replace(/\r/g, "")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();

  const text_original_length = text.length;
  const truncated = text.length > MAX_CHARS;
  if (truncated) {
    text = text.substring(0, MAX_CHARS);
  }

  item.json = {
    ...j,
    document_text: text,
    text_original_length,
    text_truncated: truncated,
    file_name: bin.fileName ?? j.file_name ?? null,
    mime_type: bin.mimeType ?? j.mime_type ?? null,
    received_at: j.received_at ?? new Date().toISOString(),
  };

  return item;
});

// Salida estructurada: ensambla metadatos + output de la IA.

return items.map((item) => {
  const data = item.json || {};
  const o = data.output || {};

  const now = new Date().toISOString();
  const project_id = `PLIEGO-${now.replace(/[-:TZ.]/g, "").slice(0, 14)}`;

  item.json = {
    project_id,
    processed_at: now,
    source: {
      file_name: data.file_name ?? null,
      mime_type: data.mime_type ?? null,
      received_at: data.received_at ?? null,
      text_original_length: data.text_original_length ?? null,
      text_truncated: data.text_truncated ?? false,
    },
    ...data,
  };

  return item;
});
